// ── @WebMvcTest: test controller layer only ───────────────────
@WebMvcTest(UserController.class)  // loads ONLY UserController and web infra
class UserControllerTest {

    @Autowired MockMvc mvc;         // auto-configured HTTP simulator

    @MockBean UserService service;  // Spring-managed mock — replaces real service

    @Test
    void getUser_returnsMappedDto() throws Exception {
        // given
        User user = new User(1L, "Alice", "alice@test.com");
        given(service.findById(1L)).willReturn(Optional.of(user));

        // when + then
        mvc.perform(get("/api/users/1")
                .contentType(MediaType.APPLICATION_JSON))
            .andExpect(status().isOk())
            .andExpect(jsonPath("$.name").value("Alice"))
            .andExpect(jsonPath("$.email").value("alice@test.com"));

        verify(service).findById(1L);
    }

    @Test
    void getUser_notFound_returns404() throws Exception {
        given(service.findById(99L)).willReturn(Optional.empty());

        mvc.perform(get("/api/users/99"))
            .andExpect(status().isNotFound());
    }

    @Test
    void createUser_invalidEmail_returns400() throws Exception {
        String badRequest = "{\"name\":\"Alice\",\"email\":\"not-an-email\"}";

        mvc.perform(post("/api/users")
                .contentType(MediaType.APPLICATION_JSON)
                .content(badRequest))
            .andExpect(status().isBadRequest())
            .andExpect(jsonPath("$.error").exists());

        verifyNoInteractions(service); // validation failed before hitting service
    }
}

// ── @DataJpaTest: test repository layer only ──────────────────
@DataJpaTest  // loads JPA + H2 by default; no web beans, no service beans
// @AutoConfigureTestDatabase(replace = NONE) // uncomment to use real DB
class UserRepositoryTest {

    @Autowired UserRepository repo;
    @Autowired TestEntityManager em;  // helper for setting up test data

    @Test
    void findByEmail_returnsUser() {
        // given — persist test data through TestEntityManager
        User user = em.persistAndFlush(new User(null, "Bob", "bob@test.com"));

        // when
        Optional<User> found = repo.findByEmail("bob@test.com");

        // then
        assertThat(found).isPresent();
        assertThat(found.get().getId()).isEqualTo(user.getId());
    }

    @Test
    void findByEmail_notFound_returnsEmpty() {
        Optional<User> found = repo.findByEmail("nobody@test.com");
        assertThat(found).isEmpty();
    }

    @Test
    void findTopLearnersByXp_returnsOrdered() {
        // given — 3 users with different XP
        em.persistAndFlush(new User(null, "C", "c@t.com", 100));
        em.persistAndFlush(new User(null, "A", "a@t.com", 500));
        em.persistAndFlush(new User(null, "B", "b@t.com", 300));

        // when
        List<User> top2 = repo.findTopByOrderByXpDesc(PageRequest.of(0, 2));

        // then
        assertThat(top2).hasSize(2);
        assertThat(top2.get(0).getName()).isEqualTo("A"); // highest XP first
        assertThat(top2.get(1).getName()).isEqualTo("B");
    }
}

// ── @JsonTest: test serialization only ───────────────────────
@JsonTest
class UserDtoJsonTest {

    @Autowired JacksonTester<UserDto> json;

    @Test
    void serialize_includesAllFields() throws Exception {
        UserDto dto = new UserDto(1L, "Alice", "alice@test.com");
        assertThat(json.write(dto))
            .hasJsonPathValue("$.id")
            .hasJsonPathStringValue("$.name")
            .extractingJsonPathStringValue("$.email").isEqualTo("alice@test.com");
    }

    @Test
    void deserialize_parsesCorrectly() throws Exception {
        String content = "{\"id\":1,\"name\":\"Alice\",\"email\":\"alice@test.com\"}";
        assertThat(json.parse(content)).isEqualTo(new UserDto(1L, "Alice", "alice@test.com"));
    }
}

