import java.util.*;

public class Q3 {
    static String classify(String desc) {
        String d = desc.toLowerCase();
        if (d.contains("serial") || d.contains("json") && !d.contains("controller") && !d.contains("endpoint"))
            return "@JsonTest";
        if (d.contains("controller") || d.contains("http status") || d.contains("rest endpoint")
                || d.contains("404") || d.contains("200") || d.contains("401") || d.contains("returns 4")
                || d.contains("not found") && !d.contains("jpql"))
            return "@WebMvcTest";
        if (d.contains("jpql") || d.contains("query") || d.contains("repository") || d.contains("findby"))
            return "@DataJpaTest";
        return "@SpringBootTest";
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt(); sc.nextLine();
        for (int i = 0; i < n; i++)
            System.out.println(classify(sc.nextLine()));
    }
}

